div.p:
pos: "struct Position" {
shape: sql_table
style.fill: "#BBDEFB"
offset_0: "x: float32" {constraint: "4 bytes"}
offset_4: "y: float32" {constraint: "4 bytes"}
size: "sizeof = 8 bytes"
}

vel: "struct Velocity" {
shape: sql_table
style.fill: "#C8E6C9"
offset_0: "dx: float32" {constraint: "4 bytes"}
offset_4: "dy: float32" {constraint: "4 bytes"}
size: "sizeof = 8 bytes"
}

health: "struct Health" {
shape: sql_table
style.fill: "#FFCDD2"
offset_0: "hp: uint16" {constraint: "2 bytes"}
offset_2: "padding: uint16" {constraint: "2 bytes (aligned)"}
size: "sizeof = 4 bytes"
}

ai: "struct AIState" {
shape: sql_table
style.fill: "#E1BEE7"
offset_0: "state: enum8" {constraint: "1 byte"}
offset_1: "padding: uint8[3]" {constraint: "3 bytes (aligned)"}
size: "sizeof = 4 bytes"
}
}

Entity_0: {
shape: hexagon
label: "EID: 0"
style.fill: "#B8D4E8"
}
Entity_4: {
shape: hexagon
label: "EID: 4"
style.fill: "#E1DBFE"
}
Entity_6: {
shape: hexagon
label: "EID: 6"
style.fill: "#F4DBFE"
}

note: "Maps EntityID -> (ArchetypeID, RowIndex)" {
shape: text
style.italic: true
}
}

empty: "Archetype [Ø]\n(Null Signature)" {
shape: rectangle
style.fill: "#EEEEEE"
style.stroke-dash: 3
}
